import{_ as t,o as s,i as a,ad as o}from"./chunks/framework.By85nKlP.js";const h=JSON.parse('{"title":"Conformance","description":"csv-pipe is verified with a curated edge-case corpus, the external csv-spectrum suite, and property-based testing, all in CI.","frontmatter":{"description":"csv-pipe is verified with a curated edge-case corpus, the external csv-spectrum suite, and property-based testing, all in CI."},"headers":[],"relativePath":"guide/conformance.md","filePath":"guide/conformance.md","lastUpdated":1782753107000}'),i={name:"guide/conformance.md"};function r(d,e,n,c,u,l){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="conformance" tabindex="-1">Conformance <a class="header-anchor" href="#conformance" aria-label="Permalink to &quot;Conformance&quot;">​</a></h1><p>CSV looks simple, but it is full of edge cases. csv-pipe handles them, and three layers of tests run on every commit.</p><h2 id="a-curated-corpus" tabindex="-1">A curated corpus <a class="header-anchor" href="#a-curated-corpus" aria-label="Permalink to &quot;A curated corpus&quot;">​</a></h2><p>Over 70 cases, each paired with its expected output. They include what trips parsers up: quoted commas and line breaks inside a field, doubled quotes, byte-order marks, the various line endings, ragged rows, and Unicode.</p><p>A small sample, shown with <code>header: false</code> so each row is a plain array:</p><table tabindex="0"><thead><tr><th>Input</th><th>Parsed</th></tr></thead><tbody><tr><td><code>a,&quot;b,c&quot;,d</code></td><td><code>[&quot;a&quot;, &quot;b,c&quot;, &quot;d&quot;]</code></td></tr><tr><td><code>&quot;a&quot;&quot;b&quot;</code></td><td><code>[&#39;a&quot;b&#39;]</code></td></tr><tr><td><code>&quot;line 1\\nline 2&quot;</code></td><td><code>[&quot;line 1\\nline 2&quot;]</code></td></tr><tr><td><code>a,b\\r\\nc,d</code> (CRLF)</td><td><code>[&quot;a&quot;,&quot;b&quot;]</code>, <code>[&quot;c&quot;,&quot;d&quot;]</code></td></tr><tr><td><code>a\\rb</code> (lone CR)</td><td><code>[&quot;a&quot;]</code>, <code>[&quot;b&quot;]</code></td></tr><tr><td><code>a,,c</code></td><td><code>[&quot;a&quot;, &quot;&quot;, &quot;c&quot;]</code></td></tr><tr><td><code>&quot;a&quot;junk,b</code></td><td><code>[&quot;a&quot;, &quot;b&quot;]</code></td></tr><tr><td><code>&quot;ab</code> (unterminated)</td><td><code>[&quot;ab&quot;]</code></td></tr><tr><td><code>\uFEFFa,b</code> (leading BOM)</td><td><code>[&quot;a&quot;, &quot;b&quot;]</code></td></tr><tr><td><code>café,日本,😀</code></td><td><code>[&quot;café&quot;, &quot;日本&quot;, &quot;😀&quot;]</code></td></tr></tbody></table><p>The full set lives in <a href="https://github.com/martsinlabs/csv-pipe/blob/master/src/decode/conformance.cases.ts" target="_blank" rel="noreferrer"><code>conformance.cases.ts</code></a>.</p><h2 id="the-csv-spectrum-suite" tabindex="-1">The csv-spectrum suite <a class="header-anchor" href="#the-csv-spectrum-suite" aria-label="Permalink to &quot;The csv-spectrum suite&quot;">​</a></h2><p>csv-pipe also passes <a href="https://github.com/maxogden/csv-spectrum" target="_blank" rel="noreferrer">csv-spectrum</a>, a widely used third-party CSV test suite.</p><h2 id="property-based-testing" tabindex="-1">Property-based testing <a class="header-anchor" href="#property-based-testing" aria-label="Permalink to &quot;Property-based testing&quot;">​</a></h2><p>Examples only reach the cases we anticipated. For the rest, <a href="https://fast-check.dev/" target="_blank" rel="noreferrer">fast-check</a> runs a few properties over thousands of random inputs:</p><ul><li><strong>It never throws.</strong> Any string produces a well-formed result.</li><li><strong>It round-trips.</strong> Encoding data and reading it back returns the original, even with commas, quotes, and newlines in the fields.</li><li><strong>It is unaffected by chunking.</strong> The same input split into varying chunk sizes parses identically to the whole.</li></ul><h2 id="ambiguous-inputs" tabindex="-1">Ambiguous inputs <a class="header-anchor" href="#ambiguous-inputs" aria-label="Permalink to &quot;Ambiguous inputs&quot;">​</a></h2><p>A few inputs have no single right answer, so here is what csv-pipe does:</p><ul><li>It is forgiving by default: a short row is padded, a long row loses the extras, anything after a closing quote is ignored, and an unterminated quote runs to the end. Switch on <a href="./parsing-options#strict-mode"><code>strict</code></a> to reject malformed rows.</li><li><code>trim</code> strips whitespace from every field, quoted ones included.</li><li>A line that is only an empty quoted field (<code>&quot;&quot;</code>) becomes one empty field. The default <code>skipEmptyLines</code> drops it with the blanks; <code>skipEmptyLines: false</code> keeps it.</li></ul><p>See <a href="./parsing-options">Options</a> for each setting in full.</p><h2 id="run-it-yourself" tabindex="-1">Run it yourself <a class="header-anchor" href="#run-it-yourself" aria-label="Permalink to &quot;Run it yourself&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/martsinlabs/csv-pipe</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> csv-pipe</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div>`,18)])])}const m=t(i,[["render",r]]);export{h as __pageData,m as default};
